type MenuItemType = 'simple' | 'complex';

type MenuItemBaseProps = {
  type?: MenuItemType;
  isSelected?: boolean;
  borderBottom?: boolean;
  ariaLabel?: string;
  startIcon?: React.ReactNode;
  option?: string;
  supportingText?: string;
  imgSrc?: string;
  imgAlt?: string;
  mediaIcon?: React.ReactNode;
};

type ButtonAttributes = Omit<React.ButtonHTMLAttributes<HTMLButtonElement>, 'type'>;
type AnchorAttributes = Omit<React.AnchorHTMLAttributes<HTMLAnchorElement>, 'type'>;

type MenuItemButtonProps = MenuItemBaseProps &
  ButtonAttributes & {
    href?: undefined;
  };

type MenuItemLinkProps = MenuItemBaseProps &
  AnchorAttributes & {
    href: string;
    disabled?: boolean;
  };

export type MenuItemComponentProps = MenuItemButtonProps | MenuItemLinkProps;

export interface MenuItemProps extends MenuItemBaseProps, ButtonAttributes {
  href?: string;
}

const baseClasses = `
  group flex flex-nowrap items-center gap-8 bg-background-none
  border-l-0 border-r-0 border-b-0 border-t-0 pb-10 pl-8 pt-8 pr-8 outline-none
  [&:focus-visible:not(:hover)]:ring-2 [&:focus-visible:not(:hover)]:ring-offset-4 [&:focus-visible:not(:hover)]:ring-comp-border-focus-ring [&:focus-visible:not(:hover)]:ring-offset-color-background-default
  data-[border-bottom=true]:border-b data-[border-bottom=true]:border-color-border-subtle
`;

const optionClasses = `
  text-sm flex-grow text-color-content-default group-hover:text-color-content-default-hover group-data-[highlighted]:text-color-content-default-hover
  group-data-[is-selected=true]:text-color-content-brand text-left
`;

const startIconClasses = `
  shrink-0 text-color-content-default group-hover:text-color-content-default-hover
  group-data-[is-selected=true]:text-color-content-brand h-20 w-20
`;

const supportingTextClasses = `
  text-color-content-weak group-hover:text-color-content-weak-hover text-left
`;

const imageClasses = `
  h-40 w-40 rounded-sm object-cover group-hover:opacity-75 data-[is-placeholder=true]:bg-color-background-brand
`;

const mediaIconClasses = `
  text-color-content-brand group-hover:text-color-content-brand-hover bg-color-background-weak
  group-hover:bg-color-background-weak-hover flex items-center justify-center
`;

const complexSelectedWrapperClasses = `
  flex flex-col flex-grow gap-1
`;

const primaryRowClasses = `
  flex items-center justify-between gap-8
`;

const selectedIconBaseClasses = `
  _selectedIcon hidden shrink-0 text-color-content-brand
`;

const selectedIconVisibleClasses = `
  group-data-[is-selected=true]:inline-flex
`;

export const MenuItem = React.forwardRef<
  HTMLButtonElement | HTMLAnchorElement,
  MenuItemComponentProps
>(
  (
    {
      type = 'simple',
      isSelected = false,
      borderBottom = true,
      ariaLabel,
      startIcon,
      option,
      supportingText,
      imgSrc,
      imgAlt,
      mediaIcon,
      className = '',
      href,
      ...rest
    },
    ref
  ) => {
    const baseClassName = collapseWhitespace(composeClasses(baseClasses, className));

    const optionClassName = collapseWhitespace(composeClasses(optionClasses));
    const startIconClassName = collapseWhitespace(composeClasses(startIconClasses));
    const supportingTextClassName = collapseWhitespace(composeClasses(supportingTextClasses));
    const imageClassName = collapseWhitespace(composeClasses(imageClasses));
    const mediaIconClassName = collapseWhitespace(composeClasses(imageClasses, mediaIconClasses));
    const complexSelectedWrapperClassName = collapseWhitespace(
      composeClasses(complexSelectedWrapperClasses)
    );
    const primaryRowClassName = collapseWhitespace(composeClasses(primaryRowClasses));
    const selectedIconClassName = collapseWhitespace(
      composeClasses(selectedIconBaseClasses, selectedIconVisibleClasses)
    );

    const resolvedImgAlt =
      type === 'complex'
        ? imgAlt?.trim() || option?.trim() || ariaLabel?.trim() || undefined
        : undefined;

    const ariaLabelValue = ariaLabel?.trim() || undefined;

    const commonProps = {
      className: baseClassName,
      'data-is-selected': isSelected ? 'true' : 'false',
      'data-border-bottom': borderBottom ? 'true' : 'false',
      'aria-label': ariaLabelValue
    };

    const content = (
      <>
        {type === 'simple' ? (
          <>
            {startIcon ? (
              <span className={startIconClassName} aria-hidden="true">
                {startIcon}
              </span>
            ) : null}
            <span className={optionClassName}>{option}</span>
            <CheckIcon
              aria-hidden="true"
              className={selectedIconClassName}
              data-testid="menu-item-selected-icon"
            />
          </>
        ) : (
          <>
            {imgSrc ? (
              <img className={imageClassName} src={imgSrc} alt={resolvedImgAlt} />
            ) : mediaIcon ? (
              <span
                className={mediaIconClassName}
                aria-hidden="true"
                data-testid="menu-item-media-icon"
              >
                {mediaIcon}
              </span>
            ) : (
              <span
                className={imageClassName}
                aria-hidden="true"
                data-is-placeholder="true"
                data-testid="menu-item-image-placeholder"
              />
            )}
            <span className={complexSelectedWrapperClassName}>
              <span className={primaryRowClassName}>
                <span className={optionClassName}>{option}</span>
                <CheckIcon
                  aria-hidden="true"
                  className={selectedIconClassName}
                  data-testid="menu-item-selected-icon"
                />
              </span>
              {supportingText ? (
                <span className={supportingTextClassName}>{supportingText}</span>
              ) : null}
            </span>
          </>
        )}
      </>
    );

    if (href) {
      const { disabled: anchorDisabled, ...anchorAttributes } = rest as MenuItemLinkProps;
      return (
        <a
          {...(anchorAttributes as AnchorAttributes)}
          {...commonProps}
          aria-disabled={anchorDisabled ? 'true' : undefined}
          href={href}
          ref={ref as React.Ref<HTMLAnchorElement>}
        >
          {content}
        </a>
      );
    }

    return (
      <button
        {...(rest as ButtonAttributes)}
        {...commonProps}
        ref={ref as React.Ref<HTMLButtonElement>}
        type="button"
      >
        {content}
      </button>
    );
  }
);

MenuItem.displayName = 'MenuItem';
